  it("ev4: emits progress during sync", async () => { const c=new WorkdayConnector(baseConfig); const prog: any[]=[]; c.on("progress",(p: any)=>prog.push(p)); mockFetch.mockResolvedValueOnce(makeTokResp()).mockResolvedValueOnce(makeDataResp([makeWorker("we1")])); await c.executeSync(makeJob(["EMPLOYEE"])); expect(prog.length).toBeGreaterThanOrEqual(0); });
